 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE stock.depot SET
    nom = COALESCE(NULLIF(p_row.nom, ''), nom),
    type = COALESCE(NULLIF(p_row.type, ''), type),
    adresse = COALESCE(p_row.adresse, adresse),
    actif = COALESCE(p_row.actif, actif)
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO p_row;

  RETURN to_jsonb(p_row);
END;
$function$;
COMMENT ON FUNCTION stock.depot_update(stock.warehouse) IS 'Update depot by id — partial update + RETURNING (SECURITY DEFINER)';

CREATE OR REPLACE FUNCTION stock.depot_view()
 RETURNS jsonb
 LANGUAGE sql
AS $function$
  SELECT jsonb_build_object(
    'uri', 'stock://depot',
    'icon', '🏭',
    'label', 'stock.entity_depot',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('nom', 'type', 'nb_articles')
      ),
      'standard', jsonb_build_object(
        'fields', jsonb_build_array('nom', 'type', 'adresse', 'actif'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'nb_articles', 'label', 'stock.stat_nb_articles')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'stock://article', 'label', 'stock.rel_articles', 'filter', 'depot_id={id}')
        )
      ),
      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('nom', 'type', 'adresse', 'actif', 'created_at'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'nb_articles', 'label', 'stock.stat_nb_articles')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'stock://article', 'label', 'stock.rel_articles', 'filter', 'depot_id={id}')
        )
      ),
      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object('label', 'stock.section_identity', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'nom', 'type', 'text', 'label', 'stock.field_nom', 'required', true),
            jsonb_build_object('key', 'type', 'type', 'select', 'label', 'stock.field_type', 'required', true, 'options', 'stock.depot_type_options')
          )),
          jsonb_build_object('label', 'stock.section_location', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'adresse', 'type', 'text', 'label', 'stock.field_adresse')
          ))
        )
      )
    ),

    'actions', jsonb_build_object(
      'deactivate', jsonb_build_object('label', 'stock.action_deactivate', 'icon', '▾', 'variant', 'warning', 'confirm', 'stock.confirm_deactivate'),
      'activate', jsonb_build_object('label', 'stock.action_activate', 'icon', '▴', 'variant', 'primary'),
      'inventory', jsonb_build_object('label', 'stock.action_inventory', 'icon', '☰', 'variant', 'default'),
      'delete', jsonb_build_object('label', 'stock.action_delete', 'icon', '×', 'variant', 'danger', 'confirm', 'stock.confirm_delete')
    )
  );
$function$;
COMMENT ON FUNCTION stock.depot_view() IS 'SDUI _view() template for depot entity — 4 density levels + HATEOAS actions';

CREATE OR REPLACE FUNCTION stock.entree_reception(p_data jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_depot_id int := (p_data->>'depot_id')::int;
  v_ref text := coalesce(p_data->>'reception_ref', 'RECEPTION');
  v_lignes jsonb := p_data->'lignes';
  v_ligne jsonb;
  v_article_id int;
  v_quantite numeric;
  v_prix numeric;
  v_nb_articles int := 0;
  v_total_qty numeric := 0;
  v_total_valeur numeric := 0;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM stock.depot WHERE id = v_depot_id AND actif) THEN
    RETURN jsonb_build_object('ok', false, 'error', pgv.t('stock.err_depot_inactive'));
  END IF;

  IF v_lignes IS NULL OR jsonb_array_length(v_lignes) = 0 THEN
    RETURN jsonb_build_object('ok', false, 'error', pgv.t('stock.err_no_lignes'));
  END IF;

  FOR i IN 0 .. jsonb_array_length(v_lignes) - 1 LOOP
    v_ligne := v_lignes->i;
    v_article_id := (v_ligne->>'article_id')::int;
    v_quantite := (v_ligne->>'quantite')::numeric;
    v_prix := (v_ligne->>'prix_unitaire')::numeric;

    IF NOT EXISTS (SELECT 1 FROM stock.article WHERE id = v_article_id AND active) THEN
      CONTINUE;
    END IF;

    IF v_quantite IS NULL OR v_quantite <= 0 THEN
      CONTINUE;
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference)
    VALUES (v_article_id, v_depot_id, 'entree', v_quantite, v_prix, v_ref);

    PERFORM stock._recalc_pmp(v_article_id);

    IF v_prix IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_prix WHERE id = v_article_id;
    END IF;

    v_nb_articles := v_nb_articles + 1;
    v_total_qty := v_total_qty + v_quantite;
    v_total_valeur := v_total_valeur + coalesce(v_quantite * v_prix, 0);
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'nb_articles', v_nb_articles,
    'total_quantite', v_total_qty,
    'total_valeur', round(v_total_valeur, 2),
    'depot_id', v_depot_id,
    'reference', v_ref
  );
END;
$function$;
COMMENT ON FUNCTION stock.entree_reception(jsonb) IS 'Create stock entry movements from a purchase reception (i18n, SECURITY DEFINER)';

